<?php
declare(strict_types=1);
if($path==='/api/profile'){require_login();$s=db()->prepare('SELECT username,is_admin,partner_sales_access,COALESCE(NULLIF(display_name,\'\'),username) display_name FROM users WHERE id=?');$s->execute([user()['id']]);header('Content-Type: application/json');echo json_encode($s->fetch());exit;}
if($path!=='/settings')return;require_login();
if($method==='POST'){
    verify_csrf();$displayName=trim((string)post('display_name'));if($displayName===''||mb_strlen($displayName)>120){flash('error','Display name is required and must be 120 characters or fewer.');redirect('/settings');}
    db()->prepare('UPDATE users SET display_name=? WHERE id=?')->execute([$displayName,user()['id']]);$_SESSION['user']['display_name']=$displayName;
    $saveTags=function(string $table,string $field):array{$ids=array_values(array_unique(array_filter(array_map('intval',(array)post($field,[])))));db()->prepare("DELETE FROM $table WHERE user_id=?")->execute([user()['id']]);$stmt=db()->prepare("INSERT INTO $table(user_id,tag_id) VALUES(?,?)");foreach($ids as $tagId)if(tag_access($tagId)!=='hidden')$stmt->execute([user()['id'],$tagId]);return $ids;};
    $defaultIds=$saveTags('user_default_tags','default_tags');$subscriptionIds=$saveTags('user_tag_subscriptions','subscription_tags');$frequency=in_array(post('alert_frequency'),['on_alert','daily_summary'],true)?post('alert_frequency'):'on_alert';$summaryTime=preg_match('/^([01]\d|2[0-3]):[0-5]\d$/',(string)post('daily_summary_time'))?(string)post('daily_summary_time'):'08:00';db()->prepare('INSERT INTO user_notification_preferences(user_id,alert_notifications,alert_frequency,daily_summary_time) VALUES(?,?,?,?) ON DUPLICATE KEY UPDATE alert_notifications=VALUES(alert_notifications),alert_frequency=VALUES(alert_frequency),daily_summary_time=VALUES(daily_summary_time)')->execute([user()['id'],post('alert_notifications')?1:0,$frequency,$summaryTime.':00']);
    audit('update','user_settings',user()['id'],['display_name'=>$displayName,'default_tag_ids'=>$defaultIds,'subscription_tag_ids'=>$subscriptionIds,'alert_notifications'=>post('alert_notifications')?1:0,'alert_frequency'=>$frequency,'daily_summary_time'=>$summaryTime]);flash('success','User settings and notification preferences updated.');redirect('/settings');
}
$stmt=db()->prepare('SELECT display_name,username,email FROM users WHERE id=?');$stmt->execute([user()['id']]);$profile=$stmt->fetch();$load=function(string $table):array{$stmt=db()->prepare("SELECT tag_id FROM $table WHERE user_id=?");$stmt->execute([user()['id']]);return array_map('intval',$stmt->fetchAll(PDO::FETCH_COLUMN));};$selected=$load('user_default_tags');$subscriptions=$load('user_tag_subscriptions');$tags=array_values(array_filter(all_tags(),fn($t)=>tag_access((int)$t['id'])!=='hidden'));$stmt=db()->prepare('SELECT * FROM user_notification_preferences WHERE user_id=?');$stmt->execute([user()['id']]);$notifications=$stmt->fetch()?:['alert_notifications'=>0,'alert_frequency'=>'on_alert','daily_summary_time'=>'08:00:00'];
layout('User settings',function()use($selected,$subscriptions,$tags,$profile,$notifications){?><h1>User settings</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Profile</h2><label>Display name<input name="display_name" value="<?=e($profile['display_name']?:$profile['username'])?>" maxlength="120" required><span class="muted">Your login username remains <?=e($profile['username'])?>.</span></label><hr><h2>Automatic tags for new contacts</h2><p class="muted">Selected tags are added whenever you create a contact manually or through an import.</p><label>Search automatic tags<input class="settings-tag-search" data-target="settings-default-tags" type="search" placeholder="Type a tag or group name"></label><div class="checkboxes settings-tags" id="settings-default-tags"><?php foreach($tags as $t):?><label data-tag-text="<?=e(mb_strtolower($t['name'].' '.($t['group_name']??'Ungrouped')))?>"><input type="checkbox" name="default_tags[]" value="<?=$t['id']?>" <?=in_array((int)$t['id'],$selected,true)?'checked':''?>><?=e($t['name'])?> <small><?=e($t['group_name']??'Ungrouped')?></small></label><?php endforeach?></div><hr><h2>Tag subscriptions</h2><p class="muted">Receive an email when a new contact is assigned one of these tags.</p><?php if(!$profile['email']):?><div class="flash error">Your account does not have an email address. Ask an administrator to add one before enabling notifications.</div><?php else:?><p>Notifications will be sent to <strong><?=e($profile['email'])?></strong>.</p><?php endif?><label>Search subscription tags<input class="settings-tag-search" data-target="settings-subscription-tags" type="search" placeholder="Type a tag or group name"></label><div class="checkboxes settings-tags" id="settings-subscription-tags"><?php foreach($tags as $t):?><label data-tag-text="<?=e(mb_strtolower($t['name'].' '.($t['group_name']??'Ungrouped')))?>"><input type="checkbox" name="subscription_tags[]" value="<?=$t['id']?>" <?=in_array((int)$t['id'],$subscriptions,true)?'checked':''?> <?=$profile['email']?'':'disabled'?>><?=e($t['name'])?> <small><?=e($t['group_name']??'Ungrouped')?></small></label><?php endforeach?></div><hr><h2>Alert notifications</h2><label class="switch-setting"><input type="checkbox" name="alert_notifications" value="1" <?=$notifications['alert_notifications']?'checked':''?> <?=$profile['email']?'':'disabled'?>> Email me about my CRM alerts</label><div class="form-grid"><label>Alert frequency<select name="alert_frequency"><option value="on_alert" <?=$notifications['alert_frequency']==='on_alert'?'selected':''?>>On alert</option><option value="daily_summary" <?=$notifications['alert_frequency']==='daily_summary'?'selected':''?>>Daily summary</option></select><span class="muted">On Alert sends at the alert's due time. Daily Summary combines all alerts due that day.</span></label><label id="summary-time-field">Daily summary time<input type="time" name="daily_summary_time" value="<?=e(substr($notifications['daily_summary_time'],0,5))?>"><span class="muted"><?=e(app_setting('app_timezone','America/New_York'))?></span></label></div><br><button>Save user settings</button></form><script>document.querySelectorAll('.settings-tag-search').forEach(search=>search.addEventListener('input',()=>document.querySelectorAll('#'+search.dataset.target+' label').forEach(label=>label.hidden=!label.dataset.tagText.includes(search.value.toLowerCase()))));const frequency=document.querySelector('[name=alert_frequency]'),timeField=document.querySelector('#summary-time-field');function toggleSummaryTime(){timeField.hidden=frequency.value!=='daily_summary'}frequency.addEventListener('change',toggleSummaryTime);toggleSummaryTime()</script><?php });exit;
